  1468→            return PSYNC_WRITE_ERROR;
  1469→        }
  1470→        return PSYNC_WAIT_REPLY;
  1471→    }
  1472→
  1473→    /* Reading half */
  1474→    reply = sendSynchronousCommand(SYNC_CMD_READ,fd,NULL);
  1475→    if (sdslen(reply) == 0) {
