  1505→            server.master_replid[CONFIG_RUN_ID_SIZE] = '\0';
  1506→            server.master_initial_offset = strtoll(offset,NULL,10);
  1507→            serverLog(LL_NOTICE,"Full resync from master: %s:%lld",
