  1515→    }
  1516→
  1517→    if (!strncmp(reply,"+CONTINUE",9)) {
  1518→        /* Partial resync was accepted. */
  1519→        serverLog(LL_NOTICE,
  1520→            "Successful partial resynchronization with master.");
  1521→
