  1531→            char new[CONFIG_RUN_ID_SIZE+1];
  1532→            memcpy(new,start,CONFIG_RUN_ID_SIZE);
  1533→            new[CONFIG_RUN_ID_SIZE] = '\0';
  1534→
  1535→            if (strcmp(new,server.cached_master->replid)) {
  1536→                /* Master ID changed. */
  1537→                serverLog(LL_WARNING,"Master replication ID changed to %s",new);
  1538→
  1539→                /* Set the old ID as our ID2, up to the current offset+1. */
  1540→                memcpy(server.replid2,server.cached_master->replid,
  1541→                    sizeof(server.replid2));
  1542→                server.second_replid_offset = server.master_repl_offset+1;
  1543→
  1544→                /* Update the cached master ID and our own primary ID to the
  1545→                 * new one. */
  1546→                memcpy(server.replid,new,sizeof(server.replid));
  1547→                memcpy(server.cached_master->replid,new,sizeof(server.replid));
  1548→
