  1553→
  1554→        /* Setup the replication to continue. */
  1555→        sdsfree(reply);
  1556→        replicationResurrectCachedMaster(fd);
  1557→
  1558→        /* If this instance was restarted and we read the metadata to
  1559→         * PSYNC from the persistence file, our replication backlog could
  1560→         * be still not initialized. Create it. */
  1561→        if (server.repl_backlog == NULL) createReplicationBacklog();
