  1596→/* This handler fires when the non blocking connect was able to
  1597→ * establish a connection with the master. */
  1598→void syncWithMaster(aeEventLoop *el, int fd, void *privdata, int mask) {
  1599→    char tmpfile[256], *err = NULL;
  1600→    int dfd = -1, maxtries = 5;
  1601→    int sockerr = 0, psync_result;
  1602→    socklen_t errlen = sizeof(sockerr);
  1603→    UNUSED(el);
  1604→    UNUSED(privdata);
  1605→    UNUSED(mask);
  1606→
  1607→    /* If this event fired after the user turned the instance into a master
  1608→     * with SLAVEOF NO ONE we must just return ASAP. */
  1609→    if (server.repl_state == REPL_STATE_NONE) {
  1610→        close(fd);
  1611→        return;
  1612→    }
  1613→
  1614→    /* Check for errors in the socket: after a non blocking connect() we
  1615→     * may find that the socket is in error state. */
  1616→    if (getsockopt(fd, SOL_SOCKET, SO_ERROR, &sockerr, &errlen) == -1)
  1617→        sockerr = errno;
  1618→    if (sockerr) {
  1619→        serverLog(LL_WARNING,"Error condition on socket for SYNC: %s",
  1620→            strerror(sockerr));
  1621→        goto error;
  1622→    }
  1623→
  1624→    /* Send a PING to check the master is able to reply without errors. */
  1625→    if (server.repl_state == REPL_STATE_CONNECTING) {
  1626→        serverLog(LL_NOTICE,"Non blocking connect for SYNC fired the event.");
  1627→        /* Delete the writable event so that the readable event remains
  1628→         * registered and we can wait for the PONG reply. */
  1629→        aeDeleteFileEvent(server.el,fd,AE_WRITABLE);
  1630→        server.repl_state = REPL_STATE_RECEIVE_PONG;
  1631→        /* Send the PING, don't check for errors at all, we have the timeout
  1632→         * that will take care about this. */
  1633→        err = sendSynchronousCommand(SYNC_CMD_WRITE,fd,"PING",NULL);
  1634→        if (err) goto write_error;
  1635→        return;
  1636→    }
  1637→
  1638→    /* Receive the PONG command. */
  1639→    if (server.repl_state == REPL_STATE_RECEIVE_PONG) {
  1640→        err = sendSynchronousCommand(SYNC_CMD_READ,fd,NULL);
  1641→
  1642→        /* We accept only two replies as valid, a positive +PONG reply
  1643→         * (we just check for "+") or an authentication error.
  1644→         * Note that older versions of Redis replied with "operation not
  1645→         * permitted" instead of using a proper error code, so we test
  1646→         * both. */
  1647→        if (err[0] != '+' &&
  1648→            strncmp(err,"-NOAUTH",7) != 0 &&
  1649→            strncmp(err,"-ERR operation not permitted",28) != 0)
  1650→        {
  1651→            serverLog(LL_WARNING,"Error reply to PING from master: '%s'",err);
  1652→            sdsfree(err);
  1653→            goto error;
  1654→        } else {
  1655→            serverLog(LL_NOTICE,
  1656→                "Master replied to PING, replication can continue...");
  1657→        }
  1658→        sdsfree(err);
  1659→        server.repl_state = REPL_STATE_SEND_AUTH;
  1660→    }
  1661→
  1662→    /* AUTH with the master if required. */
  1663→    if (server.repl_state == REPL_STATE_SEND_AUTH) {
  1664→        if (server.masteruser && server.masterauth) {
  1665→            err = sendSynchronousCommand(SYNC_CMD_WRITE,fd,"AUTH",
  1666→                                         server.masteruser,server.masterauth,NULL);
  1667→            if (err) goto write_error;
  1668→            server.repl_state = REPL_STATE_RECEIVE_AUTH;
  1669→            return;
  1670→        } else if (server.masterauth) {
  1671→            err = sendSynchronousCommand(SYNC_CMD_WRITE,fd,"AUTH",server.masterauth,NULL);
  1672→            if (err) goto write_error;
  1673→            server.repl_state = REPL_STATE_RECEIVE_AUTH;
  1674→            return;
  1675→        } else {
  1676→            server.repl_state = REPL_STATE_SEND_PORT;
  1677→        }
  1678→    }
  1679→
  1680→    /* Receive AUTH reply. */
  1681→    if (server.repl_state == REPL_STATE_RECEIVE_AUTH) {
  1682→        err = sendSynchronousCommand(SYNC_CMD_READ,fd,NULL);
  1683→        if (err[0] == '-') {
  1684→            serverLog(LL_WARNING,"Unable to AUTH to MASTER: %s",err);
  1685→            sdsfree(err);
  1686→            goto error;
  1687→        }
  1688→        sdsfree(err);
  1689→        server.repl_state = REPL_STATE_SEND_PORT;
  1690→    }
  1691→
  1692→    /* Set the slave port, so that Master's INFO command can list the
  1693→     * slave listening port correctly. */
  1694→    if (server.repl_state == REPL_STATE_SEND_PORT) {
  1695→        sds port = sdsfromlonglong(server.slave_announce_port ?
  1696→            server.slave_announce_port : server.port);
  1697→        err = sendSynchronousCommand(SYNC_CMD_WRITE,fd,"REPLCONF",
  1698→                "listening-port",port, NULL);

