  2134→/* ---------------------- MASTER CACHING FOR PSYNC -------------------------- */
  2135→
  2136→/* In order to implement partial synchronization we need to be able to cache
  2137→ * our master's client structure after a transient disconnection.
  2138→ * It is cached into server.cached_master and flushed away using the following
  2139→ * functions. */
  2140→
  2141→/* This function is called by freeClient() in order to cache the master
  2142→ * client structure instead of destroying it. freeClient() will return
  2143→ * ASAP after this function returns, so every action needed to avoid problems
  2144→ * with a client that is really "suspended" has to be done by this function.
  2145→ *
  2146→ * The other functions that will deal with the cached master are:
  2147→ *
  2148→ * replicationDiscardCachedMaster() that will make sure to kill the client
  2149→ * as for some reason we don't want to use it in the future.
  2150→ *
  2151→ * replicationResurrectCachedMaster() that is used after a successful PSYNC
  2152→ * handshake in order to reactivate the cached master.
  2153→ */
  2154→void replicationCacheMaster(client *c) {
  2155→    serverAssert(server.master != NULL && server.cached_master == NULL);
  2156→    serverLog(LL_NOTICE,"Caching the disconnected master state.");
  2157→
  2158→    /* Unlink the client from the server structures. */
  2159→    unlinkClient(c);
  2160→
  2161→    /* Reset the master client so that's ready to accept new commands:
  2162→     * we want to discard te non processed query buffers and non processed
  2163→     * offsets, including pending transactions, already populated arguments,
  2164→     * pending outputs to the master. */
  2165→    sdsclear(server.master->querybuf);
  2166→    sdsclear(server.master->pending_querybuf);
  2167→    server.master->read_reploff = server.master->reploff;
  2168→    if (c->flags & CLIENT_MULTI) discardTransaction(c);
  2169→    listEmpty(c->reply);
  2170→    c->sentlen = 0;
  2171→    c->reply_bytes = 0;
  2172→    c->bufpos = 0;
  2173→    resetClient(c);
  2174→
  2175→    /* Save the master. Server.master will be set to null later by
  2176→     * replicationHandleMasterDisconnection(). */
  2177→    server.cached_master = server.master;
  2178→
  2179→    /* Invalidate the Peer ID cache. */
  2180→    if (c->peerid) {
  2181→        sdsfree(c->peerid);
  2182→        c->peerid = NULL;
  2183→    }
  2184→
  2185→    /* Caching the master happens instead of the actual freeClient() call,
  2186→     * so make sure to adjust the replication state. This function will
  2187→     * also set server.master to NULL. */
  2188→    replicationHandleMasterDisconnection();
  2189→}
  2190→
  2191→/* This function is called when a master is turend into a slave, in order to
  2192→ * create from scratch a cached master for the new client, that will allow
  2193→ * to PSYNC with the slave that was promoted as the new master after a
  2194→ * failover.
  2195→ *
  2196→ * Assuming this instance was previously the master instance of the new master,
  2197→ * the new master will accept its replication ID, and potentiall also the
  2198→ * current offset if no data was lost during the failover. So we use our
  2199→ * current replication ID and offset in order to synthesize a cached master. */
  2200→void replicationCacheMasterUsingMyself(void) {
  2201→    /* The master client we create can be set to any DBID, because
  2202→     * the new master will start its replication stream with SELECT. */
  2203→    server.master_initial_offset = server.master_repl_offset;
  2204→    replicationCreateMasterClient(-1,-1);
  2205→
  2206→    /* Use our own ID / offset. */
  2207→    memcpy(server.master->replid, server.replid, sizeof(server.replid));
  2208→
  2209→    /* Set as cached master. */
  2210→    unlinkClient(server.master);
  2211→    server.cached_master = server.master;
  2212→    server.master = NULL;
  2213→    serverLog(LL_NOTICE,"Before turning into a replica, using my master parameters to synthesize a cached master: I may be able to synchronize with the new master with just a partial transfer.");
  2214→}
