  2216→/* Free a cached master, called when there are no longer the conditions for
  2217→ * a partial resync on reconnection. */
  2218→void replicationDiscardCachedMaster(void) {
  2219→    if (server.cached_master == NULL) return;
  2220→
  2221→    serverLog(LL_NOTICE,"Discarding previously cached master state.");
  2222→    server.cached_master->flags &= ~CLIENT_MASTER;
  2223→    freeClient(server.cached_master);
  2224→    server.cached_master = NULL;
  2225→}
  2226→
  2227→/* Turn the cached master into the current master, using the file descriptor
  2228→ * passed as argument as the socket for the new master.
  2229→ *
  2230→ * This function is called when successfully setup a partial resynchronization
  2231→ * so the stream of data that we'll receive will start from were this
  2232→ * master left. */
  2233→void replicationResurrectCachedMaster(int newfd) {
  2234→    server.master = server.cached_master;
  2235→    server.cached_master = NULL;
  2236→    server.master->fd = newfd;
  2237→    server.master->flags &= ~(CLIENT_CLOSE_AFTER_REPLY|CLIENT_CLOSE_ASAP);
  2238→    server.master->authenticated = 1;
  2239→    server.master->lastinteraction = server.unixtime;
  2240→    server.repl_state = REPL_STATE_CONNECTED;
  2241→    server.repl_down_since = 0;
  2242→
  2243→    /* Re-add to the list of clients. */
  2244→    linkClient(server.master);
  2245→    if (aeCreateFileEvent(server.el, newfd, AE_READABLE,
