  2247→        serverLog(LL_WARNING,"Error resurrecting the cached master, impossible to add the readable handler: %s", strerror(errno));
  2248→        freeClientAsync(server.master); /* Close ASAP. */
  2249→    }
  2250→
  2251→    /* We may also need to install the write handler as well if there is
  2252→     * pending data in the write buffers. */
  2253→    if (clientHasPendingReplies(server.master)) {
