  2256→            serverLog(LL_WARNING,"Error resurrecting the cached master, impossible to add the writable handler: %s", strerror(errno));
  2257→            freeClientAsync(server.master); /* Close ASAP. */
  2258→        }
  2259→    }
  2260→}
