  2262→/* ------------------------- MIN-SLAVES-TO-WRITE  --------------------------- */
  2263→
  2264→/* This function counts the number of slaves with lag <= min-slaves-max-lag.
  2265→ * If the option is active, the server will prevent writes if there are not
  2266→ * enough connected slaves with the specified lag (or less). */
  2267→void refreshGoodSlavesCount(void) {
  2268→    listIter li;
  2269→    listNode *ln;
  2270→    int good = 0;
  2271→
  2272→    if (!server.repl_min_slaves_to_write ||
  2273→        !server.repl_min_slaves_max_lag) return;
  2274→
  2275→    listRewind(server.slaves,&li);
  2276→    while((ln = listNext(&li))) {
  2277→        client *slave = ln->value;
  2278→        time_t lag = server.unixtime - slave->repl_ack_time;
  2279→
  2280→        if (slave->replstate == SLAVE_STATE_ONLINE &&
  2281→            lag <= server.repl_min_slaves_max_lag) good++;
  2282→    }
  2283→    server.repl_good_slaves_count = good;
  2284→}
