  2369→
  2370→/* ----------------------- SYNCHRONOUS REPLICATION --------------------------
  2371→ * Redis synchronous replication design can be summarized in points:
  2372→ *
  2373→ * - Redis masters have a global replication offset, used by PSYNC.
  2374→ * - Master increment the offset every time new commands are sent to slaves.
  2375→ * - Slaves ping back masters with the offset processed so far.
  2376→ *
  2377→ * So synchronous replication adds a new WAIT command in the form:
  2378→ *
  2379→ *   WAIT <num_replicas> <milliseconds_timeout>
  2380→ *
  2381→ * That returns the number of replicas that processed the query when
  2382→ * we finally have at least num_replicas, or when the timeout was
  2383→ * reached.
  2384→ *
  2385→ * The command is implemented in this way:
  2386→ *
  2387→ * - Every time a client processes a command, we remember the replication
  2388→ *   offset after sending that command to the slaves.
  2389→ * - When WAIT is called, we ask slaves to send an acknowledgement ASAP.
  2390→ *   The client is blocked at the same time (see blocked.c).
  2391→ * - Once we receive enough ACKs for a given offset or when the timeout
  2392→ *   is reached, the WAIT command is unblocked and the reply sent to the
  2393→ *   client.
  2394→ */
  2395→
  2396→/* This just set a flag so that we broadcast a REPLCONF GETACK command
  2397→ * to all the slaves in the beforeSleep() function. Note that this way
  2398→ * we "group" all the clients that want to wait for synchronouns replication
  2399→ * in a given event loop iteration, and send a single GETACK for them all. */
  2400→void replicationRequestAckFromSlaves(void) {
  2401→    server.get_ack_from_slaves = 1;
  2402→}
  2403→
  2404→/* Return the number of slaves that already acknowledged the specified
  2405→ * replication offset. */
  2406→int replicationCountAcksByOffset(long long offset) {
  2407→    listIter li;
  2408→    listNode *ln;
  2409→    int count = 0;
  2410→
  2411→    listRewind(server.slaves,&li);
  2412→    while((ln = listNext(&li))) {
  2413→        client *slave = ln->value;
  2414→
  2415→        if (slave->replstate != SLAVE_STATE_ONLINE) continue;
  2416→        if (slave->repl_ack_off >= offset) count++;
  2417→    }
  2418→    return count;
  2419→}
  2420→
  2421→/* WAIT for N replicas to acknowledge the processing of our latest
  2422→ * write command (and all the previous commands). */
  2423→void waitCommand(client *c) {
  2424→    mstime_t timeout;
  2425→    long numreplicas, ackreplicas;
  2426→    long long offset = c->woff;
  2427→
  2428→    if (server.masterhost) {
  2429→        addReplyError(c,"WAIT cannot be used with replica instances. Please also note that since Redis 4.0 if a replica is configured to be writable (which is not the default) writes to replicas are just local and are not propagated.");
  2430→        return;
  2431→    }
  2432→
  2433→    /* Argument parsing. */
  2434→    if (getLongFromObjectOrReply(c,c->argv[1],&numreplicas,NULL) != C_OK)
  2435→        return;
  2436→    if (getTimeoutFromObjectOrReply(c,c->argv[2],&timeout,UNIT_MILLISECONDS)
  2437→        != C_OK) return;
  2438→
  2439→    /* First try without blocking at all. */
  2440→    ackreplicas = replicationCountAcksByOffset(c->woff);
  2441→    if (ackreplicas >= numreplicas || c->flags & CLIENT_MULTI) {
  2442→        addReplyLongLong(c,ackreplicas);
  2443→        return;
  2444→    }
  2445→
  2446→    /* Otherwise block the client and put it into our list of clients
  2447→     * waiting for ack from slaves. */
  2448→    c->bpop.timeout = timeout;
  2449→    c->bpop.reploffset = offset;
  2450→    c->bpop.numreplicas = numreplicas;
  2451→    listAddNodeTail(server.clients_waiting_acks,c);
  2452→    blockClient(c,BLOCKED_WAIT);
  2453→
  2454→    /* Make sure that the server will send an ACK request to all the slaves
  2455→     * before returning to the event loop. */
  2456→    replicationRequestAckFromSlaves();
  2457→}
  2458→
  2459→/* This is called by unblockClient() to perform the blocking op type
  2460→ * specific cleanup. We just remove the client from the list of clients
  2461→ * waiting for replica acks. Never call it directly, call unblockClient()
  2462→ * instead. */
  2463→void unblockClientWaitingReplicas(client *c) {
  2464→    listNode *ln = listSearchKey(server.clients_waiting_acks,c);
  2465→    serverAssert(ln != NULL);
  2466→    listDelNode(server.clients_waiting_acks,ln);
  2467→}
  2468→
  2469→/* Check if there are clients blocked in WAIT that can be unblocked since
  2470→ * we received enough ACKs from slaves. */
  2471→void processClientsWaitingReplicas(void) {
  2472→    long long last_offset = 0;
  2473→    int last_numreplicas = 0;
  2474→
  2475→    listIter li;
  2476→    listNode *ln;
  2477→
  2478→    listRewind(server.clients_waiting_acks,&li);
  2479→    while((ln = listNext(&li))) {
  2480→        client *c = ln->value;
  2481→
  2482→        /* Every time we find a client that is satisfied for a given
  2483→         * offset and number of replicas, we remember it so the next client
  2484→         * may be unblocked without calling replicationCountAcksByOffset()
  2485→         * if the requested offset / replicas were equal or less. */
  2486→        if (last_offset && last_offset > c->bpop.reploffset &&
  2487→                           last_numreplicas > c->bpop.numreplicas)
  2488→        {
  2489→            unblockClient(c);
  2490→            addReplyLongLong(c,last_numreplicas);
  2491→        } else {
  2492→            int numreplicas = replicationCountAcksByOffset(c->bpop.reploffset);
  2493→
  2494→            if (numreplicas >= c->bpop.numreplicas) {
  2495→                last_offset = c->bpop.reploffset;
  2496→                last_numreplicas = numreplicas;
  2497→                unblockClient(c);
  2498→                addReplyLongLong(c,numreplicas);
  2499→            }
  2500→        }
  2501→    }
  2502→}
