  2504→/* Return the slave replication offset for this instance, that is
  2505→ * the offset for which we already processed the master replication stream. */
  2506→long long replicationGetSlaveOffset(void) {
  2507→    long long offset = 0;
  2508→
  2509→    if (server.masterhost != NULL) {
  2510→        if (server.master) {
  2511→            offset = server.master->reploff;
  2512→        } else if (server.cached_master) {
  2513→            offset = server.cached_master->reploff;
  2514→        }
  2515→    }
  2516→    /* offset may be -1 when the master does not support it at all, however
  2517→     * this function is designed to return an offset that can express the
  2518→     * amount of data processed by the master, so we return a positive
  2519→     * integer. */
  2520→    if (offset < 0) offset = 0;
  2521→    return offset;
  2522→}
