  2524→/* --------------------------- REPLICATION CRON  ---------------------------- */
  2525→
  2526→/* Replication cron function, called 1 time per second. */
  2527→void replicationCron(void) {
  2528→    static long long replication_cron_loops = 0;
  2529→
  2530→    /* Non blocking connection timeout? */
  2531→    if (server.masterhost &&
  2532→        (server.repl_state == REPL_STATE_CONNECTING ||
  2533→         slaveIsInHandshakeState()) &&
  2534→         (time(NULL)-server.repl_transfer_lastio) > server.repl_timeout)
  2535→    {
  2536→        serverLog(LL_WARNING,"Timeout connecting to the MASTER...");
  2537→        cancelReplicationHandshake();
  2538→    }
  2539→
  2540→    /* Bulk transfer I/O timeout? */
  2541→    if (server.masterhost && server.repl_state == REPL_STATE_TRANSFER &&
  2542→        (time(NULL)-server.repl_transfer_lastio) > server.repl_timeout)
  2543→    {
  2544→        serverLog(LL_WARNING,"Timeout receiving bulk data from MASTER... If the problem persists try to set the 'repl-timeout' parameter in redis.conf to a larger value.");
  2545→        cancelReplicationHandshake();
  2546→    }
  2547→
  2548→    /* Timed out master when we are an already connected slave? */
  2549→    if (server.masterhost && server.repl_state == REPL_STATE_CONNECTED &&
  2550→        (time(NULL)-server.master->lastinteraction) > server.repl_timeout)
  2551→    {
  2552→        serverLog(LL_WARNING,"MASTER timeout: no data nor PING received...");
  2553→        freeClient(server.master);
  2554→    }
  2555→
  2556→    /* Check if we should connect to a MASTER */
  2557→    if (server.repl_state == REPL_STATE_CONNECT) {
  2558→        serverLog(LL_NOTICE,"Connecting to MASTER %s:%d",
  2559→            server.masterhost, server.masterport);
  2560→        if (connectWithMaster() == C_OK) {
  2561→            serverLog(LL_NOTICE,"MASTER <-> REPLICA sync started");
  2562→        }
  2563→    }
  2564→
  2565→    /* Send ACK to master from time to time.
  2566→     * Note that we do not send periodic acks to masters that don't
  2567→     * support PSYNC and replication offsets. */
  2568→    if (server.masterhost && server.master &&
  2569→        !(server.master->flags & CLIENT_PRE_PSYNC))
  2570→        replicationSendAck();
  2571→
  2572→    /* If we have attached slaves, PING them from time to time.
  2573→     * So slaves can implement an explicit timeout to masters, and will
  2574→     * be able to detect a link disconnection even if the TCP connection
  2575→     * will not actually go down. */
  2576→    listIter li;
  2577→    listNode *ln;
  2578→    robj *ping_argv[1];
  2579→
  2580→    /* First, send PING according to ping_slave_period. */
  2581→    if ((replication_cron_loops % server.repl_ping_slave_period) == 0 &&
  2582→        listLength(server.slaves))
  2583→    {
  2584→        ping_argv[0] = createStringObject("PING",4);
  2585→        replicationFeedSlaves(server.slaves, server.slaveseldb,
  2586→            ping_argv, 1);
  2587→        decrRefCount(ping_argv[0]);
  2588→    }
  2589→
  2590→    /* Second, send a newline to all the slaves in pre-synchronization
  2591→     * stage, that is, slaves waiting for the master to create the RDB file.
  2592→     *
  2593→     * Also send the a newline to all the chained slaves we have, if we lost
  2594→     * connection from our master, to keep the slaves aware that their
  2595→     * master is online. This is needed since sub-slaves only receive proxied
  2596→     * data from top-level masters, so there is no explicit pinging in order
  2597→     * to avoid altering the replication offsets. This special out of band
  2598→     * pings (newlines) can be sent, they will have no effect in the offset.
  2599→     *

